import{c as e,Q as s,j as t,m as i}from"./chunks/framework.DYp_ty9j.js";const k=JSON.parse('{"title":"Headlamp Kubernetes Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/headlamp.md","filePath":"showcases/headlamp.md","lastUpdated":1779873774000}'),n={name:"showcases/headlamp.md"};function r(l,a,h,o,p,d){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="headlamp-kubernetes-dashboard" tabindex="-1">Headlamp Kubernetes Dashboard <a class="header-anchor" href="#headlamp-kubernetes-dashboard" aria-label="Permalink to &quot;Headlamp Kubernetes Dashboard&quot;">​</a></h1><h3 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h3><p><a href="https://headlamp.dev/" target="_blank" rel="noreferrer">Headlamp</a> is a web-based Kubernetes dashboard. It provides an intuitive interface for managing and monitoring Kubernetes clusters, allowing users to visualize cluster resources, view logs, and perform various administrative tasks. In this showcase, we will deploy Headlamp on our k3d cluster to demonstrate how it can be used for cluster inspection and management. More details here:</p><ul><li><a href="https://headlamp.dev/docs/latest/" target="_blank" rel="noreferrer">https://headlamp.dev/docs/latest/</a></li><li><a href="https://github.com/kubernetes-sigs/headlamp" target="_blank" rel="noreferrer">https://github.com/kubernetes-sigs/headlamp</a></li></ul><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>You can install Headlamp with the following startup command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/headlamp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>A token for logging in to the dashboard can be created with the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> headlamp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kube-system</span></span></code></pre></div><h3 id="show-headlamp-ui" tabindex="-1">Show Headlamp UI <a class="header-anchor" href="#show-headlamp-ui" aria-label="Permalink to &quot;Show Headlamp UI&quot;">​</a></h3><p>The setup script auto-detects your ingress controller and configures access accordingly.</p><p><strong>With an ingress controller (HAProxy, Traefik, or Kong):</strong></p><p>The Headlamp UI is exposed via <code>Ingress</code> or <code>HTTPRoute</code>. Open it in a browser: <a href="https://dashboard.127-0-0-1.nip.io:8081/" target="_blank" rel="noreferrer">https://dashboard.127-0-0-1.nip.io:8081/</a></p><p><strong>Without an ingress controller:</strong></p><p>Use a port-forward instead:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kube-system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/headlamp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9080:80</span></span></code></pre></div><p>Then open: <a href="http://localhost:9080" target="_blank" rel="noreferrer">http://localhost:9080</a></p>`,17)])])}const u=e(n,[["render",r]]);export{k as __pageData,u as default};
